import{_ as t,o,c as s,ag as l}from"./chunks/framework.D4v4AkDZ.js";const u=JSON.parse('{"title":"Tiempos Verbales","description":"Guía completa de tiempos verbales en inglés - Simple Present, Past Simple, Future","frontmatter":{"title":"Tiempos Verbales","description":"Guía completa de tiempos verbales en inglés - Simple Present, Past Simple, Future","tags":["grammar","tenses"]},"headers":[],"relativePath":"gramatica/tiempos-verbales.md","filePath":"gramatica/tiempos-verbales.md"}'),r={name:"gramatica/tiempos-verbales.md"};function i(a,e,n,p,c,m){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="⏱️-tiempos-verbales" tabindex="-1">⏱️ Tiempos Verbales <a class="header-anchor" href="#⏱️-tiempos-verbales" aria-label="Permalink to &quot;⏱️ Tiempos Verbales&quot;">​</a></h1><h2 id="simple-present-presente-simple" tabindex="-1">Simple Present (Presente Simple) <a class="header-anchor" href="#simple-present-presente-simple" aria-label="Permalink to &quot;Simple Present (Presente Simple)&quot;">​</a></h2><p><strong>Uso:</strong> Acciones habituales, hechos generales.</p><p><strong>Estructura:</strong></p><ul><li>Afirmativo: <code>Subject + verb (base) + complement</code></li><li>Negativo: <code>Subject + do/does + not + verb + complement</code></li><li>Interrogativo: <code>Do/Does + subject + verb + complement?</code></li></ul><p><strong>Ejemplos:</strong></p><ul><li>She <strong>works</strong> every day.</li><li>He <strong>does not</strong> play soccer.</li><li><strong>Do</strong> they <strong>speak</strong> English?</li></ul><hr><h2 id="past-simple-pasado-simple" tabindex="-1">Past Simple (Pasado Simple) <a class="header-anchor" href="#past-simple-pasado-simple" aria-label="Permalink to &quot;Past Simple (Pasado Simple)&quot;">​</a></h2><p><strong>Uso:</strong> Acciones completadas en el pasado.</p><p><strong>Estructura:</strong></p><ul><li>Afirmativo: <code>Subject + verb (past) + complement</code></li><li>Negativo: <code>Subject + did + not + verb + complement</code></li><li>Interrogativo: <code>Did + subject + verb + complement?</code></li></ul><p><strong>Ejemplos:</strong></p><ul><li>I <strong>studied</strong> last night.</li><li>She <strong>did not</strong> come to class.</li><li><strong>Did</strong> you <strong>finish</strong> the homework?</li></ul><hr><h2 id="future-with-will" tabindex="-1">Future with &quot;Will&quot; <a class="header-anchor" href="#future-with-will" aria-label="Permalink to &quot;Future with &quot;Will&quot;&quot;">​</a></h2><p><strong>Uso:</strong> Predicciones, decisiones espontáneas.</p><p><strong>Estructura:</strong></p><ul><li>Afirmativo: <code>Subject + will + verb + complement</code></li><li>Negativo: <code>Subject + will + not + verb + complement</code></li><li>Interrogativo: <code>Will + subject + verb + complement?</code></li></ul><p><strong>Ejemplos:</strong></p><ul><li>I <strong>will travel</strong> next year.</li><li>They <strong>won&#39;t</strong> be late.</li><li><strong>Will</strong> she <strong>call</strong> you?</li></ul><hr><blockquote><p>Agrega más tiempos verbales a medida que los estudies.</p></blockquote>',23)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
